(function () {
  function html2pdf() {
    const state = {
      element: null,
      options: {
        filename: "document.pdf",
        margin: 18,
      },
    };

    return {
      set(options) {
        state.options = Object.assign({}, state.options, options || {});
        return this;
      },
      from(element) {
        state.element = element;
        return this;
      },
      async save() {
        if (!state.element) {
          throw new Error("html2pdf: missing source element");
        }

        const canvas = await renderElementToCanvas(state.element);
        const pdfBinary = buildPdfFromCanvas(canvas, state.options);
        const blob = new Blob([binaryStringToUint8Array(pdfBinary)], {
          type: "application/pdf",
        });
        const link = document.createElement("a");
        const url = URL.createObjectURL(blob);

        link.href = url;
        link.download = state.options.filename || "document.pdf";
        link.click();

        setTimeout(function () {
          URL.revokeObjectURL(url);
        }, 1000);
      },
    };
  }

  async function renderElementToCanvas(element) {
    const rect = element.getBoundingClientRect();
    const width = Math.ceil(rect.width);
    const height = Math.ceil(element.scrollHeight || rect.height);
    const scale = Math.max(2, Math.min(window.devicePixelRatio || 1, 3));
    const clone = element.cloneNode(true);

    await inlineStyles(element, clone);
    await inlineImages(element, clone);

    const wrapper = document.createElement("div");
    wrapper.setAttribute("xmlns", "http://www.w3.org/1999/xhtml");
    wrapper.style.width = width + "px";
    wrapper.style.background = "#ffffff";
    wrapper.appendChild(clone);

    const svg = `
      <svg xmlns="http://www.w3.org/2000/svg" width="${width}" height="${height}">
        <foreignObject width="100%" height="100%">${new XMLSerializer().serializeToString(
          wrapper
        )}</foreignObject>
      </svg>
    `;

    const svgBlob = new Blob([svg], {
      type: "image/svg+xml;charset=utf-8",
    });
    const svgUrl = URL.createObjectURL(svgBlob);

    try {
      const image = await loadImage(svgUrl);
      const canvas = document.createElement("canvas");
      const context = canvas.getContext("2d");

      canvas.width = Math.ceil(width * scale);
      canvas.height = Math.ceil(height * scale);
      context.scale(scale, scale);
      context.fillStyle = "#ffffff";
      context.fillRect(0, 0, width, height);
      context.drawImage(image, 0, 0, width, height);

      return canvas;
    } finally {
      URL.revokeObjectURL(svgUrl);
    }
  }

  async function inlineStyles(sourceNode, targetNode) {
    applyComputedStyle(sourceNode, targetNode);

    const sourceChildren = sourceNode.children || [];
    const targetChildren = targetNode.children || [];

    for (let index = 0; index < sourceChildren.length; index += 1) {
      await inlineStyles(sourceChildren[index], targetChildren[index]);
    }
  }

  function applyComputedStyle(source, target) {
    const computed = window.getComputedStyle(source);
    let cssText = "";

    for (let index = 0; index < computed.length; index += 1) {
      const property = computed[index];
      cssText += property + ":" + computed.getPropertyValue(property) + ";";
    }

    target.setAttribute("style", cssText);
  }

  async function inlineImages(sourceNode, targetNode) {
    if (sourceNode.tagName === "IMG" && targetNode.tagName === "IMG") {
      targetNode.setAttribute("src", await imageToDataUrl(sourceNode));
    }

    const sourceChildren = sourceNode.children || [];
    const targetChildren = targetNode.children || [];

    for (let index = 0; index < sourceChildren.length; index += 1) {
      await inlineImages(sourceChildren[index], targetChildren[index]);
    }
  }

  async function imageToDataUrl(imageElement) {
    if (imageElement.src.startsWith("data:")) {
      return imageElement.src;
    }

    const image = await loadImage(imageElement.src);
    const canvas = document.createElement("canvas");
    const context = canvas.getContext("2d");

    canvas.width = image.naturalWidth || image.width;
    canvas.height = image.naturalHeight || image.height;
    context.drawImage(image, 0, 0);

    return canvas.toDataURL("image/png");
  }

  function loadImage(src) {
    return new Promise(function (resolve, reject) {
      const image = new Image();
      image.onload = function () {
        resolve(image);
      };
      image.onerror = reject;
      image.src = src;
    });
  }

  function buildPdfFromCanvas(canvas, options) {
    const pageWidth = 595.28;
    const pageHeight = 841.89;
    const margin = Number(options.margin) || 18;
    const usableWidth = pageWidth - margin * 2;
    const usableHeight = pageHeight - margin * 2;
    const imageWidth = canvas.width;
    const imageHeight = canvas.height;
    const scale = Math.min(usableWidth / imageWidth, usableHeight / imageHeight);
    const drawWidth = imageWidth * scale;
    const drawHeight = imageHeight * scale;
    const x = margin + (usableWidth - drawWidth) / 2;
    const y = margin + (usableHeight - drawHeight) / 2;
    const jpegBinary = dataUrlToBinaryString(canvas.toDataURL("image/jpeg", 0.92));

    const content =
      "q\n" +
      drawWidth.toFixed(2) +
      " 0 0 " +
      drawHeight.toFixed(2) +
      " " +
      x.toFixed(2) +
      " " +
      y.toFixed(2) +
      " cm\n/Im0 Do\nQ";

    const objects = [];
    const offsets = [];

    function addObject(body) {
      offsets.push(binaryLength(objects.join("")));
      objects.push(offsets.length + " 0 obj\n" + body + "\nendobj\n");
    }

    objects.push("%PDF-1.3\n");
    addObject("<< /Type /Catalog /Pages 2 0 R >>");
    addObject("<< /Type /Pages /Kids [3 0 R] /Count 1 >>");
    addObject(
      "<< /Type /Page /Parent 2 0 R /MediaBox [0 0 595.28 841.89] /Resources << /XObject << /Im0 4 0 R >> /ProcSet [/PDF /ImageC] >> /Contents 5 0 R >>"
    );
    addObject(
      "<< /Type /XObject /Subtype /Image /Width " +
        imageWidth +
        " /Height " +
        imageHeight +
        " /ColorSpace /DeviceRGB /BitsPerComponent 8 /Filter /DCTDecode /Length " +
        binaryLength(jpegBinary) +
        " >>\nstream\n" +
        jpegBinary +
        "\nendstream"
    );
    addObject("<< /Length " + binaryLength(content) + " >>\nstream\n" + content + "\nendstream");

    const xrefStart = binaryLength(objects.join(""));
    const totalObjects = offsets.length + 1;

    objects.push("xref\n0 " + totalObjects + "\n");
    objects.push("0000000000 65535 f \n");

    offsets.forEach(function (offset) {
      objects.push(String(offset).padStart(10, "0") + " 00000 n \n");
    });

    objects.push(
      "trailer\n<< /Size " +
        totalObjects +
        " /Root 1 0 R >>\nstartxref\n" +
        xrefStart +
        "\n%%EOF"
    );

    return objects.join("");
  }

  function dataUrlToBinaryString(dataUrl) {
    return atob(dataUrl.split(",")[1]);
  }

  function binaryLength(value) {
    return value.length;
  }

  function binaryStringToUint8Array(binary) {
    const bytes = new Uint8Array(binary.length);

    for (let index = 0; index < binary.length; index += 1) {
      bytes[index] = binary.charCodeAt(index) & 255;
    }

    return bytes;
  }

  window.html2pdf = html2pdf;
})();
